# Auto-labeler: heuristic triage assistant
# Runs on new bugs to pre-fill S/P and suggested owner.
import re
from dataclasses import dataclass

OWNERSHIP = {
    "hallucination":   "ai-platform",
    "regression":      "ai-platform",
    "configuration":   "product-eng",
    "infrastructure":  "infra",
    "eval":            "data-ml",
}

@dataclass
class RawBug:
    title: str
    body: str
    reporter: str

def infer_type(bug: RawBug) -> str:
    title_lower = bug.title.lower()
    body_lower  = bug.body.lower()
    text = title_lower + " " + body_lower
    if any(w in text for w in ["hallucin", "made up", "wrong fact", "fabricat"]):
        return "hallucination"
    if any(w in text for w in ["after update", "model update", "regression", "broke after"]):
        return "regression"
    if any(w in text for w in ["system prompt", "prompt change", "wrong persona"]):
        return "configuration"
    if any(w in text for w in ["timeout", "tool call failed", "latency", "rate limit"]):
        return "infrastructure"
    if any(w in text for w in ["eval", "evaluator", "benchmark"]):
        return "eval"
    return "configuration"  # safest default

def triage(bug: RawBug) -> dict:
    bug_type = infer_type(bug)
    owner    = OWNERSHIP[bug_type]
    return {
        "type":     bug_type,
        "owner":    owner,
        "action":   "DRI please confirm S/P label and verify suggested owner.",
    }

# Example
b = RawBug(
    title="Agent responded with completely wrong capital city",
    body="User asked what the capital of Australia is. Agent said Sydney.",
    reporter="user-123",
)
result = triage(b)
print(result)
# {'type': 'hallucination', 'owner': 'ai-platform', 'action': 'DRI please confirm...'}
